-- Question 9: Longest consecutive login streak per user
WITH login_dates AS (
  SELECT user_id,
    login_date,
    login_date - ROW_NUMBER() OVER (
      PARTITION BY user_id
      ORDER BY login_date
    ) * DATE('now', '+1 days') AS grp
  FROM user_logins
)
SELECT user_id,
  COUNT(*) AS streak_length,
  MIN(login_date) AS start_date,
  MAX(login_date) AS end_date
FROM login_dates
GROUP BY user_id,
  grp
ORDER BY streak_length DESC;
-- Input table: user_logins
CREATE TABLE user_logins (
  user_id VARCHAR(255),
  login_date VARCHAR(255)
);
