-- Question 10: Recursive query: full reporting chain for each employee
WITH RECURSIVE reporting_chain AS (
  SELECT id,
    name,
    manager_id,
    1 AS level
  FROM employees
  WHERE manager_id IS NULL
  UNION ALL
  SELECT e.id,
    e.name,
    e.manager_id,
    rc.level + 1
  FROM employees e
    JOIN reporting_chain rc ON e.manager_id = rc.id
)
SELECT *
FROM reporting_chain
ORDER BY level,
  id;
-- Input table: employees
CREATE TABLE employees (
  id VARCHAR(255),
  name VARCHAR(255),
  manager_id VARCHAR(255)
);
