-- Question 31: Detect circular references in the employee-manager hierarchy
WITH RECURSIVE mgr_path(id, manager_id, path) AS (
  SELECT id,
    manager_id,
    ARRAY [id]
  FROM employees
  WHERE manager_id IS NOT NULL
  UNION ALL
  SELECT e.id,
    e.manager_id,
    path || e.id
  FROM employees e
    JOIN mgr_path mp ON e.manager_id = mp.id
  WHERE NOT e.id = ANY(path)
)
SELECT DISTINCT id
FROM mgr_path
WHERE id = ANY(path);
