-- Question 34: Employees whose salary is a prime number
WITH primes AS (
  SELECT generate_series(
      2,
      (
        SELECT MAX(salary)
        FROM employees
      )
    ) AS num
  EXCEPT
  SELECT DISTINCT s.num
  FROM generate_series(
      2,
      (
        SELECT MAX(salary)
        FROM employees
      )
    ) s(num)
    JOIN generate_series(
      2,
      FLOOR(
        SQRT(
          (
            SELECT MAX(salary)
            FROM employees
          )
        )
      )::int
    ) d(div) ON s.num % d.div = 0
    AND s.num <> d.div
)
SELECT *
FROM employees
WHERE salary IN (
    SELECT num
    FROM primes
  );
