-- Question 49: Consecutive days where sales exceeded a threshold
WITH flagged AS (
  SELECT sale_date,
    amount,
    sale_date - ROW_NUMBER() OVER (
      ORDER BY sale_date
    ) * DATE('now', '+1 days') AS grp
  FROM sales
  WHERE amount > 1000
)
SELECT MIN(sale_date) AS start_date,
  MAX(sale_date) AS end_date,
  COUNT(*) AS consecutive_days
FROM flagged
GROUP BY grp
ORDER BY consecutive_days DESC;
