-- Question 56: Year-over-year sales growth percentage
WITH monthly_sales AS (
  SELECT strftime('%Y-%m-01', sale_date) AS month,
    SUM(amount) AS total_sales
  FROM sales
  GROUP BY month
)
SELECT ms1.month,
  ms1.total_sales,
  (
    (ms1.total_sales - ms2.total_sales) * 100.0 / ms2.total_sales
  ) AS growth_pct
FROM monthly_sales ms1
  LEFT JOIN monthly_sales ms2 ON ms1.month = ms2.month + INTERVAL '1 year';
