-- Question 60: Top 3 products by total sales amount each month
WITH monthly_product_sales AS (
  SELECT product_id,
    strftime('%Y-%m-01', sale_date) AS month,
    SUM(amount) AS total_sales
  FROM sales
  GROUP BY product_id,
    month
),
ranked_sales AS (
  SELECT *,
    RANK() OVER (
      PARTITION BY month
      ORDER BY total_sales DESC
    ) AS sales_rank
  FROM monthly_product_sales
)
SELECT product_id,
  month,
  total_sales
FROM ranked_sales
WHERE sales_rank <= 3
ORDER BY month,
  sales_rank;
