-- Question 78: Percentage contribution of each product to monthly sales
WITH monthly_sales AS (
  SELECT product_id,
    strftime('%Y-%m-01', sale_date) AS month,
    SUM(amount) AS prod_sales
  FROM sales
  GROUP BY product_id,
    month
),
total_monthly AS (
  SELECT month,
    SUM(prod_sales) AS total
  FROM monthly_sales
  GROUP BY month
)
SELECT ms.product_id,
  ms.month,
  ms.prod_sales,
  (ms.prod_sales * 100.0) / tms.total AS pct
FROM monthly_sales ms
  JOIN total_monthly tms ON ms.month = tms.month;
