-- Question 83: Month-over-month sales % change per product
WITH monthly_sales AS (
  SELECT product_id,
    strftime('%Y-%m-01', sale_date) AS month,
    SUM(amount) AS total_sales
  FROM sales
  GROUP BY product_id,
    month
)
SELECT product_id,
  month,
  total_sales,
  (
    total_sales - LAG(total_sales) OVER (
      PARTITION BY product_id
      ORDER BY month
    )
  ) * 100.0 / LAG(total_sales) OVER (
    PARTITION BY product_id
    ORDER BY month
  ) AS pct_change
FROM monthly_sales;
