-- Question 87: Customer with the highest purchase amount per year
WITH yearly_sales AS (
  SELECT customer_id,
    EXTRACT(
      YEAR
      FROM sale_date
    ) AS year,
    SUM(amount) AS total_amount
  FROM sales
  GROUP BY customer_id,
    year
),
ranked_sales AS (
  SELECT *,
    RANK() OVER (
      PARTITION BY year
      ORDER BY total_amount DESC
    ) AS rnk
  FROM yearly_sales
)
SELECT customer_id,
  year,
  total_amount
FROM ranked_sales
WHERE rnk = 1;
