-- Question 108: Customer with the longest gap between consecutive orders
WITH ordered AS (
  SELECT customer_id,
    order_date,
    LAG(order_date) OVER (
      PARTITION BY customer_id
      ORDER BY order_date
    ) AS prev
  FROM orders
),
gaps AS (
  SELECT customer_id,
    order_date - prev AS gap_days
  FROM ordered
  WHERE prev IS NOT NULL
)
SELECT customer_id,
  MAX(gap_days) AS longest_gap
FROM gaps
GROUP BY customer_id
ORDER BY longest_gap DESC
LIMIT 1;
