-- Question 152: Average gap in days between orders per customer
WITH ordered AS (
  SELECT customer_id,
    order_date,
    LAG(order_date) OVER (
      PARTITION BY customer_id
      ORDER BY order_date
    ) AS prev
  FROM orders
),
gaps AS (
  SELECT customer_id,
    order_date - prev AS gap
  FROM ordered
  WHERE prev IS NOT NULL
)
SELECT customer_id,
  AVG(gap) AS avg_gap_days
FROM gaps
GROUP BY customer_id;
