-- Question 156: Top 3 products by quantity sold in each category
SELECT category_id,
  product_id,
  total_quantity
FROM (
    SELECT p.category_id,
      s.product_id,
      SUM(s.quantity) AS total_quantity,
      ROW_NUMBER() OVER (
        PARTITION BY p.category_id
        ORDER BY SUM(s.quantity) DESC
      ) AS rn
    FROM sales s
      JOIN products p ON s.product_id = p.product_id
    GROUP BY p.category_id,
      s.product_id
  ) sub
WHERE rn <= 3;
