-- Question 167: Employees earning above company avg but below their dept avg
WITH company_avg AS (
  SELECT AVG(salary) AS avg_salary
  FROM employees
),
dept_avg AS (
  SELECT dept_id,
    AVG(salary) AS avg_salary
  FROM employees
  GROUP BY dept_id
)
SELECT e.*
FROM employees e,
  company_avg ca
  JOIN dept_avg da ON e.dept_id = da.dept_id
WHERE e.salary > ca.avg_salary
  AND e.salary < da.avg_salary;
