-- Question 181: Products whose sales doubled vs the previous month
WITH monthly_sales AS (
  SELECT product_id,
    strftime('%Y-%m-01', sale_date) AS month,
    SUM(amount) AS total_sales
  FROM sales
  GROUP BY product_id,
    month
),
sales_comparison AS (
  SELECT product_id,
    month,
    total_sales,
    LAG(total_sales) OVER (
      PARTITION BY product_id
      ORDER BY month
    ) AS prev_sales
  FROM monthly_sales
)
SELECT product_id,
  month
FROM sales_comparison
WHERE prev_sales IS NOT NULL
  AND total_sales >= 2 * prev_sales;
-- Input table: sales
CREATE TABLE sales (
  product_id VARCHAR(255),
  month VARCHAR(255),
  total_sales VARCHAR(255)
);
