-- Question 196: Customers whose orders increased 20 %+ month-over-month
WITH monthly_orders AS (
  SELECT customer_id,
    strftime('%Y-%m-01', order_date) AS month,
    COUNT(*) AS cnt
  FROM orders
  GROUP BY customer_id,
    month
),
orders_comparison AS (
  SELECT customer_id,
    month,
    cnt,
    LAG(cnt) OVER (
      PARTITION BY customer_id
      ORDER BY month
    ) AS prev
  FROM monthly_orders
)
SELECT customer_id,
  month
FROM orders_comparison
WHERE prev IS NOT NULL
  AND cnt >= 1.2 * prev;
