-- Question 203: Top 3 employees with highest salary increase over last year
WITH last_year AS (
  SELECT employee_id,
    salary AS ly
  FROM salaries
  WHERE year = EXTRACT(
      YEAR
      FROM CURRENT_DATE
    ) - 1
),
this_year AS (
  SELECT employee_id,
    salary AS ty
  FROM salaries
  WHERE year = EXTRACT(
      YEAR
      FROM CURRENT_DATE
    )
)
SELECT t.employee_id,
  t.ty - l.ly AS salary_increase
FROM this_year t
  JOIN last_year l ON t.employee_id = l.employee_id
ORDER BY salary_increase DESC
LIMIT 3;
-- Input table: salaries
