-- Question 204: Employees with the longest consecutive workday streak
WITH workdays AS (
  SELECT employee_id,
    work_date,
    work_date - ROW_NUMBER() OVER (
      PARTITION BY employee_id
      ORDER BY work_date
    ) * DATE('now', '+1 days') AS grp
  FROM attendance
),
consecutive AS (
  SELECT employee_id,
    COUNT(*) AS streak
  FROM workdays
  GROUP BY employee_id,
    grp
)
SELECT employee_id,
  MAX(streak) AS max_streak
FROM consecutive
GROUP BY employee_id;
