-- Question 208: Customers who ordered every month for the last 6 months
WITH months AS (
  SELECT generate_series(
      strftime('%Y-%m-01', CURRENT_DATE) - INTERVAL '5 months',
      strftime('%Y-%m-01', CURRENT_DATE),
      INTERVAL '1 month'
    ) AS month
),
customer_months AS (
  SELECT customer_id,
    strftime('%Y-%m-01', order_date) AS month
  FROM orders
  WHERE order_date >= DATE('now', '- 6 months')
  GROUP BY customer_id,
    month
)
SELECT customer_id
FROM customer_months cm
  JOIN months m ON cm.month = m.month
GROUP BY customer_id
HAVING COUNT(DISTINCT cm.month) = 6;
