-- Question 225: Customers who spent more than the average in their country
WITH avg_by_country AS (
  SELECT c.country,
    AVG(o.amount) AS avg_amount
  FROM customers c
    JOIN orders o ON c.customer_id = o.customer_id
  GROUP BY c.country
)
SELECT c.customer_id,
  SUM(o.amount) AS total_spent
FROM customers c
  JOIN orders o ON c.customer_id = o.customer_id
  JOIN avg_by_country a ON c.country = a.country
GROUP BY c.customer_id,
  c.country,
  a.avg_amount
HAVING SUM(o.amount) > a.avg_amount;
-- Input table: customers + orders
CREATE TABLE customers + orders (
  customer_id VARCHAR(255),
  country VARCHAR(255),
  total_spent VARCHAR(255),
  country_avg VARCHAR(255)
