-- Question 231: Customer retention rate month-over-month
WITH monthly_customers AS (
  SELECT customer_id,
    strftime('%Y-%m-01', order_date) AS month
  FROM orders
  GROUP BY customer_id,
    month
),
retention AS (
  SELECT curr.month AS current_month,
    curr.customer_id
  FROM monthly_customers curr
    JOIN monthly_customers prev ON curr.customer_id = prev.customer_id
    AND curr.month = prev.month + INTERVAL '1 month'
)
SELECT current_month,
  COUNT(DISTINCT customer_id) * 100.0 / (
    SELECT COUNT(DISTINCT customer_id)
    FROM monthly_customers
    WHERE month = current_month - INTERVAL '1 month'
  ) AS retention_rate
FROM retention
GROUP BY current_month
ORDER BY current_month;
-- Input table: orders
CREATE TABLE orders (
  customer_id VARCHAR(255),
  order_date VARCHAR(255)
);
