-- Question 241: Products with an increasing sales trend over 3 months
WITH monthly_sales AS (
  SELECT product_id,
    strftime('%Y-%m-01', sale_date) AS month,
    SUM(amount) AS total_sales
  FROM sales
  WHERE sale_date >= DATE('now', '- 3 months')
  GROUP BY product_id,
    month
),
sales_ranked AS (
  SELECT product_id,
    month,
    total_sales,
    LAG(total_sales) OVER (
      PARTITION BY product_id
      ORDER BY month
    ) AS prev1,
    LAG(total_sales, 2) OVER (
      PARTITION BY product_id
      ORDER BY month
    ) AS prev2
  FROM monthly_sales
)
SELECT DISTINCT product_id
FROM sales_ranked
WHERE total_sales > prev1
  AND prev1 > prev2;
-- Input table: monthly sales
CREATE TABLE monthly sales (
  product_id VARCHAR(255),
  month VARCHAR(255),
  total_sales VARCHAR(255)
);
