-- Question 253: Customers with 3 consecutive months of increasing orders
WITH monthly_orders AS (
  SELECT customer_id,
    strftime('%Y-%m-01', order_date) AS month,
    COUNT(*) AS cnt
  FROM orders
  GROUP BY customer_id,
    month
),
orders_with_lag AS (
  SELECT customer_id,
    month,
    cnt,
    LAG(cnt, 1) OVER (
      PARTITION BY customer_id
      ORDER BY month
    ) AS prev1,
    LAG(cnt, 2) OVER (
      PARTITION BY customer_id
      ORDER BY month
    ) AS prev2
  FROM monthly_orders
)
SELECT DISTINCT customer_id
FROM orders_with_lag
WHERE cnt > prev1
  AND prev1 > prev2;
