  GROUP BY dept_id
),
last_year AS (
  SELECT dept_id,
    COUNT(*) AS cnt
  FROM employees
  WHERE hire_date <= CURRENT_DATE - INTERVAL '1 year'
    AND (
      termination_date IS NULL
      OR termination_date >= CURRENT_DATE - INTERVAL '1 year'
    )
  GROUP BY dept_id
)
SELECT c.dept_id,
  c.cnt - COALESCE(l.cnt, 0) AS increase
FROM current_year c
  LEFT JOIN last_year l ON c.dept_id = l.dept_id
ORDER BY increase DESC
LIMIT 1;
-- Input table: employees
CREATE TABLE employees (
  dept_id VARCHAR(255),
  employees_now VARCHAR(255),
  employees_last_year VARCHAR(255)
);
