-- Question 272: Employees whose salaries increased every single year
WITH salary_diff AS (
  SELECT employee_id,
    year,
    salary,
    LAG(salary) OVER (
      PARTITION BY employee_id
      ORDER BY year
    ) AS prev_salary
  FROM salaries
)
SELECT employee_id
FROM salary_diff
WHERE salary > prev_salary
  OR prev_salary IS NULL
GROUP BY employee_id
HAVING COUNT(*) = (
    SELECT COUNT(DISTINCT year)
    FROM salaries
    WHERE employee_id = salary_diff.employee_id
  );
