-- Question 274: Day with the highest sales in each month
WITH daily_sales AS (
  SELECT DATE(order_date) AS day,
    SUM(amount) AS total_sales
  FROM orders
  GROUP BY day
),
ranked_sales AS (
  SELECT day,
    total_sales,
    RANK() OVER (
      PARTITION BY strftime('%Y-%m-01', day)
      ORDER BY total_sales DESC
    ) AS sales_rank
  FROM daily_sales
)
SELECT day,
  total_sales
FROM ranked_sales
WHERE sales_rank = 1;
