-- Question 275: Products with the highest sales increase vs previous month
WITH monthly_sales AS (
  SELECT product_id,
    strftime('%Y-%m-01', sale_date) AS month,
    SUM(amount) AS total_sales
  FROM sales
  GROUP BY product_id,
    month
),
sales_diff AS (
  SELECT product_id,
    month,
    total_sales,
    LAG(total_sales) OVER (
      PARTITION BY product_id
      ORDER BY month
    ) AS prev_month_sales
  FROM monthly_sales
)
SELECT product_id,
  month,
  total_sales - prev_month_sales AS increase
FROM sales_diff
WHERE prev_month_sales IS NOT NULL
ORDER BY increase DESC
LIMIT 10;
-- Input table: sales
CREATE TABLE sales (
  product_id VARCHAR(255),
  month VARCHAR(255),
  total_sales VARCHAR(255)
);
