-- Question 293: Customers with the highest order count in each region
WITH customer_order_counts AS (
  SELECT c.region,
    o.customer_id,
    COUNT(*) AS order_count,
    ROW_NUMBER() OVER (
      PARTITION BY c.region
      ORDER BY COUNT(*) DESC
    ) AS rn
  FROM customers c
    JOIN orders o ON c.customer_id = o.customer_id
  GROUP BY c.region,
    o.customer_id
)
SELECT region,
  customer_id,
  order_count
FROM customer_order_counts
WHERE rn = 1;
-- Input table: customers + orders
CREATE TABLE customers + orders (
  region VARCHAR(255),
  customer_id VARCHAR(255),
  order_count VARCHAR(255)
);
