-- Question 294: Flag customers with increasing orders every month this year
WITH monthly_counts AS (
  SELECT customer_id,
    strftime('%Y-%m-01', order_date) AS month,
    COUNT(*) AS cnt
  FROM orders
  WHERE EXTRACT(
      YEAR
      FROM order_date
    ) = EXTRACT(
      YEAR
      FROM CURRENT_DATE
    )
  GROUP BY customer_id,
    month
),
increase_check AS (
  SELECT customer_id,
    LAG(cnt) OVER (
      PARTITION BY customer_id
      ORDER BY month
    ) AS prev_cnt,
    cnt
  FROM monthly_counts
)
SELECT DISTINCT customer_id
FROM increase_check
WHERE cnt > prev_cnt
  AND prev_cnt IS NOT NULL;
-- Input table: monthly orders  (2025)
