-- Question 318: Find the fiscal quarter for each date (custom fiscal year starting in April)
SELECT date_col,
  CASE 
    WHEN EXTRACT(MONTH FROM date_col) BETWEEN 4 AND 6 THEN 'Q1'
    WHEN EXTRACT(MONTH FROM date_col) BETWEEN 7 AND 9 THEN 'Q2'
    WHEN EXTRACT(MONTH FROM date_col) BETWEEN 10 AND 12 THEN 'Q3'
    ELSE 'Q4'
  END AS fiscal_quarter,
  CASE 
    WHEN EXTRACT(MONTH FROM date_col) BETWEEN 4 AND 12 THEN EXTRACT(YEAR FROM date_col)
    ELSE EXTRACT(YEAR FROM date_col) - 1
  END AS fiscal_year
FROM dates;
