-- Question 320: Calculate retention rate month over month
WITH monthly_users AS (
  SELECT strftime('%Y-%m-01', signup_date) AS month,
    COUNT(DISTINCT user_id) AS users
  FROM user_signups
  GROUP BY month
)
SELECT month,
  users,
  LAG(users) OVER (ORDER BY month) AS prev_month_users,
  ROUND(users * 100.0 / NULLIF(LAG(users) OVER (ORDER BY month), 0), 2) AS retention_rate
FROM monthly_users;
-- Input table: user_signups
CREATE TABLE user_signups (
  user_id VARCHAR(255),
  signup_date DATE
