-- Question 328: Calculate project duration in business days
SELECT project_id,
  start_date,
  end_date,
  end_date - start_date AS total_days,
  SUM(CASE WHEN EXTRACT(DOW FROM d) NOT IN (0, 6)
  ) AS business_days
FROM projects,
  generate_series(start_date, end_date, '1 day') AS d
GROUP BY project_id, start_date, end_date;
