-- Question 329: Get year-to-date sales vs same period last year
SELECT 
  SUM(amount) CASE WHEN sale_date >= DATE('now', 'start of year')) AS ytd_sales,
  SUM(amount) CASE WHEN sale_date >= DATE('now', 'start of year') - INTERVAL '1 year'
      AND sale_date < DATE('now', 'start of year')
  ) AS prev_ytd_sales,
  ROUND(
    SUM(amount) CASE WHEN sale_date >= DATE('now', 'start of year')) * 100.0 /
    NULLIF(SUM(amount) CASE WHEN sale_date >= DATE('now', 'start of year') - INTERVAL '1 year'
        AND sale_date < DATE('now', 'start of year')
    ), 0) - 100, 2
  ) AS ytd_growth_pct
FROM sales;
-- Input table: sales
