-- Question 376: Find shortest path in graph
WITH RECURSIVE graph_path AS (
  SELECT start_node, end_node, 1 AS depth, ARRAY[start_node] AS path
  FROM edges
  WHERE start_node = 'A'
  UNION ALL
  SELECT e.end_node, e.end_node, gp.depth + 1, gp.path || e.end_node
  FROM edges e
  JOIN graph_path gp ON e.start_node = gp.path[array_length(gp.path, 1)]
  WHERE NOT e.end_node = ANY(gp.path)
)
SELECT path, depth FROM graph_path WHERE end_node = 'D' ORDER BY depth LIMIT 1;
-- Input table: edges
CREATE TABLE edges (
  start_node VARCHAR(255),
  end_node VARCHAR(255)
);
