-- Question 377: Generate power set
WITH RECURSIVE powerset(items, remaining, current) AS (
  SELECT ARRAY[]::TEXT[], ARRAY['A', 'B', 'C'], ARRAY[]::TEXT[]
  UNION ALL
  SELECT 
    items || remaining[1],
    remaining[2:],
    CASE WHEN remaining[1] = 'A' THEN items || remaining[1] ELSE items END
  FROM powerset
  WHERE array_length(remaining, 1) > 0
)
SELECT items FROM powerset WHERE array_length(items, 1) > 0;
