-- Question 381: Generate combinations
WITH RECURSIVE combinations(arr, index, current) AS (
  SELECT ARRAY['A', 'B', 'C'], 1, ARRAY[]::TEXT[]
  UNION ALL
  SELECT arr, index + 1, current || arr[index]
  FROM combinations
  WHERE index <= array_length(arr, 1)
)
SELECT current FROM combinations WHERE array_length(current, 1) = 2;
