-- Question 382: Find all permutations
WITH RECURSIVE permutations(remaining, current) AS (
  SELECT ARRAY['1', '2', '3'], ARRAY[]::TEXT[]
  UNION ALL
  SELECT 
    array_remove(remaining, r),
    current || r
  FROM permutations, unnest(remaining) AS r
  WHERE array_length(current, 1) < 3
)
SELECT current FROM permutations WHERE array_length(current, 1) = 3;
-- Input table: (no input)
-- Output table:
CREATE TABLE result (, depth INT);-- ======================================================================
