-- Question 384: Expand directory tree with full paths
WITH RECURSIVE dir_tree AS (
  SELECT id, name, parent_id, name AS full_path, 1 AS level
  FROM directories
  WHERE parent_id IS NULL
  UNION ALL
  SELECT d.id, d.name, d.parent_id, dt.full_path || '/' || d.name, dt.level + 1
  FROM directories d
  JOIN dir_tree dt ON d.parent_id = dt.id
)
SELECT full_path, level FROM dir_tree;
