-- Question 385: Count nodes in each subtree
WITH RECURSIVE subtree AS (
  SELECT id, 1 AS node_count
  FROM tree
  UNION ALL
  SELECT t.id, s.node_count + 1
  FROM tree t
  JOIN subtree s ON t.parent_id = s.id
)
SELECT id, SUM(node_count) - 1 AS descendant_count
FROM subtree GROUP BY id;
-- Input table: tree
