-- Question 386: Generate geometric sequence
WITH RECURSIVE geometric(a, ratio, count) AS (
  SELECT 1, 2, 1
  UNION ALL
  SELECT a * ratio, ratio, count + 1
  FROM geometric WHERE count < 10
)
SELECT a FROM geometric;
