-- Question 387: Find all paths from root to leaves
WITH RECURSIVE paths AS (
  SELECT id, name, manager_id, CAST(name AS TEXT) AS path
  FROM org
  WHERE manager_id IS NULL
  UNION ALL
  SELECT o.id, o.name, o.manager_id, p.path || ' -> ' || o.name
  FROM org o
  JOIN paths p ON o.manager_id = p.id
)
SELECT path FROM paths WHERE id NOT IN (SELECT manager_id FROM org WHERE manager_id IS NOT NULL);
