-- Question 388: Calculate nested set model depth
WITH RECURSIVE sets AS (
  SELECT id, name, left_val, right_val, 1 AS depth
  FROM nested_sets
  WHERE left_val = 1
  UNION ALL
  SELECT n.id, n.name, n.left_val, n.right_val, s.depth + 1
  FROM nested_sets n
  JOIN sets s ON n.left_val > s.left_val AND n.left_val < s.right_val
)
SELECT DISTINCT ON (id) * FROM sets;
-- Input table: nested_sets
CREATE TABLE nested_sets (
  id VARCHAR(255),
  name VARCHAR(255),
  left_val INT,
  right_val INT
);
