-- Question 389: Generate all subsequences
WITH RECURSIVE subsequences(str, i, current) AS (
  SELECT 'abc', 1, ''
  UNION ALL
  SELECT str, i + 1, current || SUBSTRING(str, i, 1)
  FROM subsequences WHERE i <= LENGTH(str)
)
SELECT DISTINCT current FROM subsequences WHERE current != '';
-- Input table: (no input)
-- Output table:
CREATE TABLE result (, depth INT);-- ======================================================================
-- Question 390: Calculate Levenshtein distance
WITH RECURSIVE levenshtein(s1, s2, i, j, dist) AS (
  SELECT 'kitten', 'sitting', 1, 1, 0
  UNION ALL
  SELECT 
    s1, s2,
    CASE WHEN i < LENGTH(s1) THEN i + 1 ELSE i END,
    CASE WHEN j < LENGTH(s2) THEN j + 1 ELSE j END,
    dist + CASE 
      WHEN SUBSTRING(s1, i, 1) != SUBSTRING(s2, j, 1) THEN 1 
      ELSE 0 
    END
  FROM levenshtein
  WHERE i <= LENGTH(s1) AND j <= LENGTH(s2)
)
SELECT MIN(dist) AS levenshtein_distance FROM levenshtein;
-- Input table: (no input)
-- Output table:
CREATE TABLE result (, depth INT);-- ======================================================================
