-- Question 444: Year-over-year pivot
SELECT 
  product_category,
  SUM(CASE WHEN EXTRACT(YEAR FROM sale_date) = 2024 THEN amount ELSE 0 END) AS Sales_2024,
  SUM(CASE WHEN EXTRACT(YEAR FROM sale_date) = 2025 THEN amount ELSE 0 END) AS Sales_2025,
  ROUND(
    (SUM(CASE WHEN EXTRACT(YEAR FROM sale_date) = 2025 THEN amount ELSE 0 END) -
     SUM(CASE WHEN EXTRACT(YEAR FROM sale_date) = 2024 THEN amount ELSE 0 END)) * 100.0 /
    NULLIF(SUM(CASE WHEN EXTRACT(YEAR FROM sale_date) = 2024 THEN amount ELSE 0 END), 0),
    2
  ) AS Growth_Pct
FROM sales
GROUP BY product_category;
-- Input table: sales
CREATE TABLE sales (
  sale_id VARCHAR(255),
  product_category VARCHAR(255),
  sale_date DATE,
  amount DECIMAL
);
