-- Question 448: Multi-attribute unpivot
SELECT 
  employee_id,
  attribute,
  value
FROM (
  SELECT 
    id AS employee_id,
    salary::TEXT AS salary,
    bonus::TEXT AS bonus,
    stock::TEXT AS stock,
    vacation_days::TEXT AS vacation
  FROM employees
) src
CROSS JOIN LATERAL UNNEST(
  ARRAY['salary', 'bonus', 'stock', 'vacation']
) WITH ORDINALITY AS u(attribute, ord)
CROSS JOIN LATERAL (
  SELECT CASE attribute
    WHEN 'salary' THEN salary
    WHEN 'bonus' THEN bonus
    WHEN 'stock' THEN stock
    WHEN 'vacation' THEN vacation
  END AS value
) v;
-- Input table: employees
CREATE TABLE employees (
  id VARCHAR(255),
  name VARCHAR(255),
  salary DECIMAL,
  bonus DECIMAL,
  stock INT,
  vacation_days INT
);
