  department,
  COUNT(*) AS Total,
  SUM(CASE WHEN status = 'Active') AS Active,
  ROUND(AVG(CASE WHEN status = 'Active' THEN salary END), 0) AS Avg_Salary_Active,
  SUM(CASE WHEN status = 'Inactive') AS Inactive,
  ROUND(AVG(CASE WHEN status = 'Inactive' THEN salary END), 0) AS Avg_Salary_Inactive
FROM employees
GROUP BY department;
